        builder.keepUnoptimizedFilesPostProcessor(cbKeepUnoptimized.isSelected());
        builder.iosCreateImagesetFolders(cbIosCreateImageset.isSelected());
        builder.guiAdvancedOptions(rbOptAdvanced.isSelected());
